{"list":[{"type":"task","center":{"x":220,"y":180},"id":"ski0qsd6qx","text":"set $recordsString","actionList":[{"formula":"// Find the related feedback records
$$backendIDs = record\findRelatedMany('CInsight', id, 'feedbackDatas', 9999,'createdAt', 'desc');

// Initialize loop variables
$i = 0;
$recordsString = '';
$count = array\length($$backendIDs);

// Loop through real records
while($i < $count) {
  $$backendID = array\at($$backendIDs, $i);

  // Fetch real attributes
  $feedbackDescription = record\attribute('CFeedbackData', $$backendID, 'feedbackDescription');
  $feedbackID = record\attribute('CFeedbackData', $$backendID, 'feedbackFormID');
  $codingLevel1 = "Placeholder";    // TODO
  $codingLevel2 = "Placeholder";    // TODO
  $codingLevel3 = "Placeholder";    // TODO
  $createdAt = record\attribute('CFeedbackData', $$backendID, 'createdAt');

  // Clean the feedback description string
  $feedbackDescription = string\replace($feedbackDescription, "\n", " ");
  $feedbackDescription = string\replace($feedbackDescription, "\r", "");
  
  // Fill metadata JSON string
  $metadata = string\concatenate(
    '{',
      '"coding_level_1": "', $codingLevel1, '", ',
      '"coding_level_2": "', $codingLevel2, '", ',
      '"coding_level_3": "', $codingLevel3, '", ',
      '"created": "', $createdAt, '", ',
      '"feedback_record_id": "', $feedbackID, '"',
    '}'
  );
  
  // Fill record-level JSON string
  $record = string\concatenate(
      '{"content": "', $feedbackDescription, '", "id": "', $feedbackID, '", ', 
      '"metadata": ', $metadata, '}'
  );

  // Add a comma between records, except first one
  if ($i == 0) {
      $recordsString = $record;
  } else {
      $recordsString = string\concatenate($recordsString, ',', $record);
  }

  $i = $i + 1;
}

$$recordsString = string\concatenate('[', $recordsString, ']');","cid":0,"id":"f21zm1kmdv","type":"executeFormula"}],"description":null},{"type":"task","center":{"x":360,"y":180},"id":"9levq1av1e","text":"select $fullEndpoint","actionList":[{"formula":"<?php // Do not copy this tag into EspoCRM
// This selects the endpoint to hit based on the method chosen in the UI

$$selectedMethod = record\attribute('CInsight', id, 'method');
$url= ext\appSecret\get('QFA_API_BASE_URL');

if ($$selectedMethod == "summarize_aggregate") {$$endpoint = "/v1/summarize-bulk";}
else if ($$selectedMethod == "analyze") {$$endpoint = "/v1/analyze-bulk";}
else {$$endpoint = "/v1/summarize-bulk";}

// Currently hard-coded until upgraded to espo 9.2.3+
$fullEndpoint = string\concatenate($url, $$endpoint);
","cid":0,"id":"9xjb2unsg3","type":"executeFormula"}],"description":null},{"type":"task","center":{"x":500,"y":180},"id":"rzhpnsh7eu","text":"combine $motherPayload","actionList":[{"formula":"// This creates a "mother" payload that can be used to hit any of the inference routes

$outputLanguage = record\attribute('CInsight', id, 'outputLanguage');
$prompt = record\attribute('CInsight', id, 'freeTextPrompt');

$motherPayload = string\concatenate(
    '{',
    '"feedback_records": ', $$recordsString, ', ',
    '"prompt": "', $prompt, '", ',
    '"output_language": "', $outputLanguage, '", ',
    '"selected_method": "', $$selectedMethod, '", ',
    '"endpoint": "', $$endpoint, '"',
    '}'
);","cid":0,"id":"iakgn85ltq","type":"executeFormula"}],"description":null},{"type":"task","center":{"x":640,"y":180},"id":"wkr4x6yr9y","text":"POST request, set modelResponse","actionList":[{"requestType":"POST","contentType":"application/json","content":"{}","requestUrl":"{$$fullEndpoint}","headers":["ngrok-skip-browser-warning: 69420","Authorization: Bearer {#secrets.QFA_API_KEY}"],"contentVariable":"$motherPayload","cid":0,"id":"kdp8p1i3fn","type":"sendRequest"},{"formula":"// This assigns the pretty_output of the bulk reponse to the
// modelResponse attribute

$response = $_lastHttpResponseBody;

modelResponse = json\retrieve($response, 'pretty_output');","cid":1,"id":"gtautkujwr","type":"executeFormula"}],"description":null},{"type":"eventEnd","center":{"x":780,"y":180},"id":"d0hc7g2kh6"},{"startId":"ski0qsd6qx","endId":"9levq1av1e","startDirection":"r","id":"g3x1k6f9lc","type":"flow"},{"startId":"9levq1av1e","endId":"rzhpnsh7eu","startDirection":"r","id":"fce1ihrzqb","type":"flow"},{"startId":"rzhpnsh7eu","endId":"wkr4x6yr9y","startDirection":"r","id":"v0wqwentos","type":"flow"},{"startId":"wkr4x6yr9y","endId":"d0hc7g2kh6","startDirection":"r","id":"4i4kjyvuay","type":"flow"},{"type":"eventStartConditional","center":{"x":60,"y":180},"triggerType":"afterRecordCreated","isInterrupting":false,"id":"d9dcscokfu","text":"When insight is saved","conditionsAll":[],"conditionsAny":[],"conditionsFormula":null,"description":null},{"startId":"d9dcscokfu","endId":"ski0qsd6qx","startDirection":"r","id":"pu4ayxgwp9","type":"flow"}],"createdEntitiesData":{}}
